#include <bits/stdc++.h>
using namespace std;
typedef long long ll;
const int N=20;
ll f[11][N];
void init(){
	for(int i=1;i<=9;i++){
		f[i][0]=1;
		for(int j=1;j<N;j++)
			f[i][j]=f[i][j-1]*i;
	}
}
ll ans(ll x){
	int n=0,a[N];
	while(x)
		a[++n]=x%10,x/=10; 
	ll res=0;
	for(int i=n;i;i--){
		for(int j=(i==n);j<min(a[i],a[n]);j++){
			if(i==n)
				res+=f[j][i-1];
			else
				res+=f[a[n]][i-1];
		}
		if(a[i]>=a[n] && i<n)
			break;
		if(i==1)
			res++;
	}
	for(int i=1;i<n;i++)
		for(int j=1;j<=9;j++)
			res+=f[j][i-1];
	return res;
}
int main(){
	init();
	ll l,r;
	scanf("%lld%lld",&l,&r);
	printf("%lld",ans(r)-ans(l-1));
	return 0;
}
